const n={async create(e){const r=localStorage.getItem("token"),o=await fetch("/api/orders",{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${r}`},body:JSON.stringify(e)});if(!o.ok){const t=await o.json().catch(()=>({}));throw new Error(t.error||"Erreur lors de la création de la commande")}return o.json()},async getMyOrders(){const e=localStorage.getItem("token"),r=await fetch("/api/orders/me",{headers:{Authorization:`Bearer ${e}`}});if(!r.ok)throw new Error("Erreur lors du chargement des commandes");return r.json()},async uploadProof(e,r){const o=localStorage.getItem("token"),t=new FormData;t.append("proof",r);const a=await fetch(`/api/orders/${e}/proof`,{method:"POST",headers:{Authorization:`Bearer ${o}`},body:t});if(!a.ok)throw new Error("Erreur lors de l'envoi de la preuve");return a.json()},async getAllForAdmin(){const e=localStorage.getItem("token"),r=await fetch("/api/admin/orders",{headers:{Authorization:`Bearer ${e}`}});if(!r.ok)throw new Error("Erreur lors du chargement des commandes admin");return r.json()},async updateStatus(e,r){const o=localStorage.getItem("token"),t=await fetch(`/api/admin/orders/${e}`,{method:"PATCH",headers:{"Content-Type":"application/json",Authorization:`Bearer ${o}`},body:JSON.stringify({status:r})});if(!t.ok)throw new Error("Erreur lors de la mise à jour du statut");return t.json()}};export{n as o};
